sql:
SELECT objects.obj_id, classes.cls_name
FROM objects
INNER JOIN classes ON objects.cls_id = classes.cls_id;

SELECT o.obj_id
FROM objects o
INNER JOIN class_instances ci ON o.cls_id = ci.cls_id;

SELECT obj_id, COUNT(instance_id) as total_instances 
FROM object_instances 
GROUP BY obj_id;

SELECT COUNT(DISTINCT obj_id) AS total_unique_objects
FROM (
    SELECT obj_id FROM objects
    UNION ALL
    SELECT obj_id FROM object_instances
);

SELECT obj_id
FROM objects o
WHERE o.obj_id IN (
    SELECT obj_id FROM object_access_logs GROUP BY obj_id HAVING COUNT(DISTINCT user_id) > 10
)
AND o.cls_id NOT IN (
    SELECT cls_id FROM class_instances WHERE instance_name = 'Deprecated'
);

SELECT cls_id, COUNT(obj_id) AS NumberOfObjects 
FROM object_class_relationships 
GROUP BY cls_id;

